1: // Provider-adapter seam for the OpenAgents inference gateway (EPIC #5474, #5476).
2: //
3: // This is the typed interface + registry that the rest of the inference build
4: // plugs into. Each provider lane registers exactly ONE adapter by id:
5: //   - #5479 Fireworks (open models)        -> registerProviderAdapter(fireworksAdapter)
6: //   - #5480 Vertex Anthropic (Claude)      -> registerProviderAdapter(vertexAdapter)
7: //   - #5481 partner passthrough            -> registerProviderAdapter(passthroughAdapter)
8: // Routing (#5482) decides WHICH adapter id handles a given model; this module
9: // owns only the contract + lookup. Adapters never touch credits, payment, or
10: // public projection — they translate a normalized request into provider tokens
11: // and return a normalized result + the provider `usage` object (receipt-first).
12: //
13: // The shape is intentionally provider-neutral and OpenAI-Chat-Completions-like
14: // so a real client works by changing only base URL + key. Anthropic Messages is
15: // a parallel surface (#5476 leaves a clean spot); both normalize into the same
16: // adapter request/result here.
17: 
18: import { Effect } from 'effect'
19: 
20: // A single chat message in the normalized request. `role`/`content` mirror the
21: // OpenAI Chat Completions shape so adapters can pass through with minimal
22: // translation.
23: export type InferenceMessage = Readonly<{
24:   role: string
25:   content: string
26:   // OpenAI-compatible tool-call replay metadata. Tool-using clients (OpenCode,
27:   // AI SDK, etc.) send prior assistant tool calls and tool results back through
28:   // the next request; adapters that speak OpenAI-compatible chat must preserve
29:   // these fields so the provider can associate each tool result with the call
30:   // that requested it.
31:   name?: string | undefined
32:   toolCallId?: string | undefined
33:   toolCalls?: ReadonlyArray<InferenceToolCall> | undefined
34: }>
35: 
36: // Normalized inference request handed to an adapter. Adapter implementations
37: // translate this into their provider's wire format. `passthroughParams` carries
38: // standard sampling params (temperature, top_p, max_tokens, ...) that the route
39: // forwards verbatim; adapters apply only the ones their provider supports.
40: export type InferenceRequest = Readonly<{
41:   model: string
42:   messages: ReadonlyArray<InferenceMessage>
43:   stream: boolean
44:   passthroughParams: Readonly<Record<string, unknown>>
45: }>
46: 
47: // Provider `usage` object — the receipt-first source of truth for metering.
48: // Adapters MUST populate this from the provider response, never an estimate
49: // (INVARIANTS.md "Canonical Token Usage Ledger" + the gateway business doc §4).
50: export type InferenceUsage = Readonly<{
51:   promptTokens: number
52:   completionTokens: number
53:   totalTokens: number
54:   // Optional cached-input dimension (e.g. Fireworks prompt-cache hits, billed
55:   // ~50% of input). Present when the provider reports it; left undefined
56:   // otherwise so the metering hook can decide how to price the difference.
57:   cachedPromptTokens?: number | undefined
58: }>
59: 
60: export type InferenceToolCall = Readonly<{
61:   id: string
62:   type: 'function'
63:   function: Readonly<{
64:     name: string
65:     arguments: string
66:   }>
67: }>
68: 
69: export type InferenceToolCallDelta = Readonly<{
70:   index: number
71:   id?: string | undefined
72:   type?: 'function' | undefined
73:   function?:
74:     | Readonly<{
75:         name?: string | undefined
76:         arguments?: string | undefined
77:       }>
78:     | undefined
79: }>
80: 
81: // Non-streaming adapter result.
82: export type InferenceResult = Readonly<{
83:   // The assistant message content for the (single) completion choice.
84:   content: string
85:   // Provider-reported finish reason ("stop", "length", ...).
86:   finishReason: string
87:   usage: InferenceUsage
88:   // Provider-native model id actually served (may differ from the requested
89:   // alias once routing/aliasing lands).
90:   servedModel: string
91:   // OpenAI-compatible assistant tool calls, present when `finishReason` is
92:   // `tool_calls` or a provider returns an assistant message that requests tools.
93:   toolCalls?: ReadonlyArray<InferenceToolCall> | undefined
94: }>
