96: // One normalized SSE frame as it is parsed off the upstream byte stream, plus
97: // the running terminal state (finishReason / usage / servedModel). This is what
98: // a TRUE pass-through stream yields incrementally: every content delta as it
99: // arrives (so the edge idle-timer resets and a multi-minute generation never
100: // 524s), and the terminal usage frame when the upstream emits it. The route
101: // re-frames these into OpenAI-compatible `data:` SSE and settles metering from
102: // the terminal usage frame once the upstream stream closes (receipt-first).
103: export type InferenceStreamEvent = Readonly<{
104:   // Incremental content for this frame (may be empty on the terminal frame).
105:   contentDelta: string
106:   // Incremental OpenAI-compatible tool-call deltas. Arguments may arrive in many
107:   // partial frames; the route must forward them as-is instead of trying to
108:   // assemble or validate the provider's JSON argument stream.
109:   toolCallDeltas?: ReadonlyArray<InferenceToolCallDelta> | undefined
110:   // Set when the upstream reports a finish reason (terminal frame).
111:   finishReason?: string | undefined
112:   // Set when the upstream emits a usage frame (terminal, receipt-first).
113:   usage?: InferenceUsage | undefined
114:   // Provider-native model id when the upstream reports one.
115:   servedModel?: string | undefined
116: }>
117: 
118: // A true incremental stream of normalized SSE events. Unlike `stream` (which
119: // returns a fully-materialized array — convenient for tests/metering but it
120: // buffers the WHOLE upstream completion before the first byte reaches the
121: // client, which is exactly what trips the Cloudflare edge ~100s idle timeout on
122: // a long generation), `streamSse` hands back a lazily-consumed source that emits
123: // each frame as the upstream produces it. The route pumps these straight to the
124: // client so bytes flow continuously and a 3-minute generation never 524s.
125: //
126: // `terminal()` resolves AFTER the source is fully drained, with the captured
127: // terminal state (finishReason / usage / servedModel) so the route can settle
128: // metering receipt-first and attach the `openagents` disclosure block — without
129: // re-buffering the content.
130: export type InferenceStreamSource = Readonly<{
131:   // Async-iterable of normalized frames, consumed once.
132:   frames: AsyncIterable<InferenceStreamEvent>
133:   // Resolves once `frames` is exhausted, with the terminal metering state.
134:   terminal: () => Readonly<{
135:     finishReason: string | undefined
136:     usage: InferenceUsage | undefined
137:     servedModel: string | undefined
138:   }>
139: }>
140: 
141: // A single streamed delta. The route serializes these into OpenAI-compatible
142: // `data:` SSE frames. The final chunk of a stream carries `usage` so the
143: // metering hook can settle from real counts.
144: export type InferenceStreamChunk = Readonly<{
145:   // Incremental content delta for this frame (may be empty on the final frame).
146:   contentDelta: string
147:   // Incremental OpenAI-compatible tool-call deltas.
148:   toolCallDeltas?: ReadonlyArray<InferenceToolCallDelta> | undefined
149:   // Set on the terminal frame only.
150:   finishReason?: string | undefined
151:   // Set on the terminal frame only (receipt-first usage).
152:   usage?: InferenceUsage | undefined
153:   // Provider-native model id actually served. Set on the terminal frame when
154:   // the adapter can resolve it; the route falls back to the requested id.
155:   servedModel?: string | undefined
156: }>
157: 
158: // Typed adapter failure. Adapters surface provider/transport problems as this
159: // rather than throwing, so the route can map them to a stable JSON error.
160: //
161: // The retry classification fields (`retryable`, `httpStatus`, `kind`) are the
162: // typed signal routing (#5482) consumes to decide backoff + overflow to another
163: // supply lane. They are OPTIONAL and default to a non-retryable, unclassified
164: // failure so existing `{ adapterId, reason }` constructions stay valid and the
165: // route can keep reading `error.reason` unchanged.
166: export class InferenceAdapterError extends Error {
167:   readonly _tag = 'InferenceAdapterError'
168:   readonly adapterId: string
169:   readonly reason: string
170:   // Whether routing may safely retry the request or overflow it to another
171:   // supply lane (e.g. provider 429/503 or a transport fault). Defaults false.
172:   readonly retryable: boolean
173:   // The upstream HTTP status when the failure came from a provider response
174:   // (e.g. 429, 503, 500); undefined for transport/config/parse failures.
175:   readonly httpStatus: number | undefined
176:   // Stable, neutral failure classification for routing/metrics, e.g.
177:   // "rate_limited", "service_overloaded", "upstream_error", "transport_error",
178:   // "configuration_error", "malformed_response", "request_rejected".
179:   readonly kind: string | undefined
180: 
181:   constructor(
182:     input: Readonly<{
183:       adapterId: string
184:       reason: string
185:       retryable?: boolean | undefined
186:       httpStatus?: number | undefined
187:       kind?: string | undefined
188:     }>,
189:   ) {
190:     super(`[${input.adapterId}] ${input.reason}`)
191:     this.name = 'InferenceAdapterError'
192:     this.adapterId = input.adapterId
193:     this.reason = input.reason
194:     this.retryable = input.retryable ?? false
195:     this.httpStatus = input.httpStatus
196:     this.kind = input.kind
197:   }
198: }
199: 
200: // The provider-adapter contract. Phase-2 adapters implement this once each.
201: export type InferenceProviderAdapter = Readonly<{
202:   // Stable adapter id, e.g. "stub-echo", "fireworks", "vertex-anthropic",
203:   // "passthrough". Used by the registry and routing.
204:   id: string
205:   // Non-streaming completion.
206:   complete: (
207:     request: InferenceRequest,
208:   ) => Effect.Effect<InferenceResult, InferenceAdapterError>
209:   // Streaming completion. Implementations yield deltas; the terminal chunk
210:   // carries `finishReason` + `usage`. NOTE: this returns a fully-materialized
211:   // array, so it BUFFERS the whole upstream completion before any byte reaches
212:   // the client. It stays for tests, metering reconstruction, and the overflow
213:   // dispatcher; the route prefers `streamSse` (below) for the live hot path so a
214:   // long generation streams through and never trips the edge idle timeout.
215:   stream: (
216:     request: InferenceRequest,
217:   ) => Effect.Effect<ReadonlyArray<InferenceStreamChunk>, InferenceAdapterError>
218:   // OPTIONAL true incremental pass-through stream. When an adapter implements
219:   // this, the route pumps the upstream SSE to the client frame-by-frame (no
220:   // server-side buffering of the whole stream), so the edge idle-timer resets on
221:   // every chunk and long generations never 524. Adapters that cannot stream
222:   // incrementally (stub/echo, simple test adapters) omit it and the route falls
223:   // back to the buffered `stream` path.
224:   streamSse?: (
225:     request: InferenceRequest,
226:   ) => Effect.Effect<InferenceStreamSource, InferenceAdapterError>
227: }>
228: 
229: // Registry: maps adapter id -> adapter. The registry is the single seam the
230: // rest of the EPIC plugs into. Routing resolves a model to an adapter id and
231: // asks the registry for the adapter; this module does not decide routing.
232: export class InferenceProviderRegistry {
233:   private readonly adapters = new Map<string, InferenceProviderAdapter>()
234: 
235:   // Register (or replace) an adapter by its id. Each provider child issue calls
236:   // this exactly once at wiring time.
237:   register(adapter: InferenceProviderAdapter): void {
238:     this.adapters.set(adapter.id, adapter)
239:   }
240: 
241:   // Resolve an adapter by id. Returns undefined when no adapter is registered
242:   // for the id (the route maps that to a stable model_unavailable error).
243:   resolve(adapterId: string): InferenceProviderAdapter | undefined {
244:     return this.adapters.get(adapterId)
245:   }
246: 
247:   // Snapshot of registered adapter ids (stable order), for diagnostics/tests.
248:   ids(): ReadonlyArray<string> {
249:     return Array.from(this.adapters.keys()).sort()
250:   }
251: }

