      { frame: { choices: [{ delta: { content: 'BBB' }, index: 0 }] }, gate: gate2 },
      {
        frame: {
          choices: [{ delta: {}, finish_reason: 'stop', index: 0 }],
          model: 'accounts/fireworks/models/kimi-k2p7-code',
          usage: { completion_tokens: 6, prompt_tokens: 12, total_tokens: 18 },
        },
        gate: gate3,
      },
    ])

