1: // The benchmark RUNNER (book P1-5 / #6088).
2: //
3: // Executes a matrix config cell-by-cell against a pluggable `BenchmarkLaneSeam`,
4: // and records the P0-1 telemetry RECORD per sample by feeding the seam's measured
5: // sample straight into the canonical `buildKhalaTelemetryRecord`. The runner
6: // REUSES the telemetry schema — it never forks a parallel metric vocabulary — so
7: // a benchmark sample and a production request are described by the exact same
8: // `openagents.khala.telemetry.v1` record. That is the whole point: the benchmark
9: // measures the SAME lifecycle fields the gateway records in production.
10: //
11: // PURE/DETERMINISTIC with the fixture seam: same config + same seam → same runs.
12: // No clock, no randomness, no network. The runner itself issues no IO; it only
13: // drives the seam and assembles telemetry records. (A real, billable sweep is
14: // achieved by passing the owner-armed real seam — gated in `lane-seam.ts`.)
15: import {
16:   type KhalaTelemetryRecord,
17:   buildKhalaTelemetryRecord,
18: } from '../khala-telemetry'
19: import type { BenchmarkCell, BenchmarkMatrixConfig } from './matrix'
20: import { expandMatrix } from './matrix'
21: import type { BenchmarkLaneSeam } from './lane-seam'
22: 
23: // One executed sample of one cell: the cell context + the canonical telemetry
24: // record. A not-yet-available lane produces NO telemetry record (it was never
25: // executed) — `record` is null and `skippedReason` says why.
26: export type BenchmarkRun = Readonly<{
27:   cellId: string
28:   cell: BenchmarkCell
29:   sampleIndex: number
30:   // The canonical lifecycle record, or null when the cell was skipped (a
31:   // not-yet-available lane is never executed — honest, not a fabricated zero).
32:   record: KhalaTelemetryRecord | null
33:   // Why a run was skipped; null when it executed.
34:   skippedReason: string | null
35: }>
36: 
37: // The full result of running a matrix config against a seam.
38: export type BenchmarkRunSet = Readonly<{
39:   configId: string
40:   // The seam that produced these runs ("fixture" | "real").
41:   seamId: string
42:   // Whether the seam that ran these was capable of real spend. The report
43:   // surfaces this so a reader knows whether numbers are illustrative or real.
44:   seamCanSpend: boolean
45:   // Every (cell × sample) run, in deterministic matrix order.
46:   runs: ReadonlyArray<BenchmarkRun>
47:   // Cell-level coverage: how many cells expanded, executed, and were skipped.
48:   cellsExpanded: number
49:   cellsExecuted: number
50:   cellsSkipped: number
51: }>
52: 
53: // Build a stable request id for a benchmark run. PURE (no UUID/clock): it encodes
54: // the config, cell, and sample index so the same run always gets the same id —
55: // reproducible and auditable, never a random handle.
56: const buildRunRequestId = (
57:   configId: string,
58:   cellId: string,
59:   sampleIndex: number,
60: ): string => `bench:${configId}:${cellId}:s${sampleIndex}`
61: 
62: // Run a single sample of a cell against the seam and assemble its telemetry
63: // record. A not-yet-available lane is NEVER executed against any seam — it yields
64: // a skipped run (honest absence), because there is no real path to measure and we
65: // refuse to fabricate one.
66: const runSample = (
67:   config: BenchmarkMatrixConfig,
68:   cell: BenchmarkCell,
69:   sampleIndex: number,
70:   seam: BenchmarkLaneSeam,
71: ): BenchmarkRun => {
72:   if (cell.laneAvailability === 'not_yet_available') {
73:     return {
74:       cellId: cell.cellId,
75:       cell,
76:       sampleIndex,
77:       record: null,
78:       skippedReason: `lane_not_yet_available:${cell.lane}`,
79:     }
80:   }
81: 
82:   const sample = seam.sample(cell, sampleIndex)
83:   const requestClass =
84:     cell.transport === 'batch'
85:       ? 'batch'
86:       : cell.workload === 'verifier-run'
87:         ? 'verifier_run'
88:         : 'interactive_stream'
89: 
90:   const record = buildKhalaTelemetryRecord({
91:     requestId: buildRunRequestId(config.id, cell.cellId, sampleIndex),
92:     requestedModel: `${cell.lane}/${cell.engine}`,
93:     servedModel: `${cell.lane}/${cell.engine}`,
94:     route: cell.workload,
95:     provider: cell.lane,
96:     requestClass,
97:     promptTokens: sample.promptTokens,
98:     completionTokens: sample.completionTokens,
99:     totalTokens: sample.totalTokens,
100:     cachedInputTokens: sample.cachedInputTokens,
101:     ttftMs: cell.transport === 'streaming' ? sample.ttftMs : undefined,
102:     totalWallClockMs: sample.totalWallClockMs,
103:     generationWallClockMs: sample.generationWallClockMs,
104:     providerTimeMs: sample.providerTimeMs,
105:     gatewayOverheadMs: sample.gatewayOverheadMs,
106:     verifierTimeMs:
107:       sample.verifierTimeMs > 0 ? sample.verifierTimeMs : undefined,
108:     region: sample.region,
109:     // Speculation disclosure (book P1-8 / #6091): the seam's per-sample
110:     // speculation outcome (mode + draft counts) flows into the canonical record
111:     // so a benchmark sample discloses speculation the same way a production
112:     // request will. Absent => the builder records the honest-unknown shape.
113:     ...(sample.speculation === undefined
114:       ? {}
115:       : { speculation: sample.speculation }),
116:     verificationClass: sample.verificationClass,
117:     executedVerdict: sample.executedVerdict,
118:     scalarReward: sample.scalarReward,
119:     costBasisMsat: sample.costBasisMsat,
120:     // The benchmark measures COST basis; it does not set a price (pricing is a
121:     // separate product concern). Margin bucket therefore stays `not_measured`.
122:     settlementState: 'not_applicable',
123:   })
124: 
125:   return {
126:     cellId: cell.cellId,
127:     cell,
128:     sampleIndex,
129:     record,
130:     skippedReason: null,
131:   }
132: }
133: 
134: // Run an entire matrix config against a seam. Expands the matrix deterministically,
135: // then runs `samplesPerCell` samples of each executable cell (one skipped run for
136: // each not-yet-available cell). PURE with the fixture seam.
137: export const runBenchmark = (
138:   config: BenchmarkMatrixConfig,
139:   seam: BenchmarkLaneSeam,
140: ): BenchmarkRunSet => {
141:   const cells = expandMatrix(config)
142:   const runs: Array<BenchmarkRun> = []
143:   let cellsExecuted = 0
144:   let cellsSkipped = 0
145: 
146:   for (const cell of cells) {
147:     if (cell.laneAvailability === 'not_yet_available') {
148:       cellsSkipped += 1
149:       runs.push(runSample(config, cell, 0, seam))
150:       continue
151:     }
152:     cellsExecuted += 1
153:     const samples = Math.max(1, Math.floor(cell.samplesPerCell))
154:     for (let sampleIndex = 0; sampleIndex < samples; sampleIndex += 1) {
155:       runs.push(runSample(config, cell, sampleIndex, seam))
156:     }
157:   }
158: 
159:   return {
160:     configId: config.id,
161:     seamId: seam.id,
162:     seamCanSpend: seam.canSpend,
163:     runs,
164:     cellsExpanded: cells.length,
165:     cellsExecuted,
166:     cellsSkipped,
167:   }
168: }

